import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { AnalyticsRepository } from '../../src/repositories/analytics.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import {
  AnalyticsRouteHandler,
  parseAnalyticsQuery,
  parseMetricType,
} from '../../src/routes/analytics.routes.js';
import type { AnalyticsQueryParams } from '../../src/routes/analytics.routes.js';

// ---------------------------------------------------------------------------
// Integration test: full pipeline (RouteHandler → Service → Repository → DB)
// ---------------------------------------------------------------------------

describe('Analytics Integration', () => {
  let db: Database;
  let repo: AnalyticsRepository;
  let service: AnalyticsService;
  let handler: AnalyticsRouteHandler;

  beforeEach(() => {
    db = new Database();
    repo = new AnalyticsRepository(db);
    service = new AnalyticsService(repo);
    handler = new AnalyticsRouteHandler(service);
  });

  // -------------------------------------------------------------------------
  // Helpers
  // -------------------------------------------------------------------------

  const validParams: AnalyticsQueryParams = {
    startDate: '2026-01-01',
    endDate: '2026-01-31',
  };

  const validParamsWithGranularity: AnalyticsQueryParams = {
    startDate: '2026-01-01',
    endDate: '2026-01-31',
    granularity: 'week',
  };

  // =========================================================================
  // parseAnalyticsQuery — validation tests
  // =========================================================================

  describe('parseAnalyticsQuery', () => {
    it('parses valid params with default granularity', () => {
      const query = parseAnalyticsQuery(validParams);

      expect(query.dateRange.start).toEqual(new Date('2026-01-01'));
      expect(query.dateRange.end).toEqual(new Date('2026-01-31'));
      expect(query.granularity).toBe('day');
    });

    it('parses valid params with explicit granularity', () => {
      const query = parseAnalyticsQuery(validParamsWithGranularity);

      expect(query.granularity).toBe('week');
    });

    it('throws on missing startDate', () => {
      expect(() =>
        parseAnalyticsQuery({ startDate: '', endDate: '2026-01-31' }),
      ).toThrow('startDate and endDate are required');
    });

    it('throws on missing endDate', () => {
      expect(() =>
        parseAnalyticsQuery({ startDate: '2026-01-01', endDate: '' }),
      ).toThrow('startDate and endDate are required');
    });

    it('throws on invalid date strings', () => {
      expect(() =>
        parseAnalyticsQuery({ startDate: 'not-a-date', endDate: '2026-01-31' }),
      ).toThrow('valid ISO 8601 dates');
    });

    it('throws when startDate >= endDate', () => {
      expect(() =>
        parseAnalyticsQuery({ startDate: '2026-02-01', endDate: '2026-01-01' }),
      ).toThrow('startDate must be before endDate');
    });

    it('throws when startDate equals endDate', () => {
      expect(() =>
        parseAnalyticsQuery({ startDate: '2026-01-01', endDate: '2026-01-01' }),
      ).toThrow('startDate must be before endDate');
    });

    it('throws on invalid granularity', () => {
      expect(() =>
        parseAnalyticsQuery({
          startDate: '2026-01-01',
          endDate: '2026-01-31',
          granularity: 'minute',
        }),
      ).toThrow('Invalid granularity');
    });

    it('accepts all valid granularities', () => {
      for (const g of ['hour', 'day', 'week', 'month']) {
        const query = parseAnalyticsQuery({
          startDate: '2026-01-01',
          endDate: '2026-01-31',
          granularity: g,
        });
        expect(query.granularity).toBe(g);
      }
    });
  });

  // =========================================================================
  // parseMetricType — validation tests
  // =========================================================================

  describe('parseMetricType', () => {
    it('accepts valid metric types', () => {
      expect(parseMetricType('orders')).toBe('orders');
      expect(parseMetricType('revenue')).toBe('revenue');
      expect(parseMetricType('users')).toBe('users');
      expect(parseMetricType('conversion')).toBe('conversion');
    });

    it('throws on invalid metric type', () => {
      expect(() => parseMetricType('invalid')).toThrow('Invalid metric type');
    });

    it('throws on empty string', () => {
      expect(() => parseMetricType('')).toThrow('Invalid metric type');
    });
  });

  // =========================================================================
  // GET /api/analytics/dashboard — full pipeline
  // =========================================================================

  describe('GET /api/analytics/dashboard', () => {
    it('returns success with dashboard data for valid params', () => {
      const result = handler.getDashboard(validParams);

      expect(result.success).toBe(true);
      expect(result.data).toBeDefined();
      expect(result.data!.metrics.orders).toBeDefined();
      expect(result.data!.metrics.revenue).toBeDefined();
      expect(result.data!.metrics.users).toBeDefined();
      expect(result.data!.metrics.conversion).toBeDefined();
    });

    it('includes dateRange matching the request', () => {
      const result = handler.getDashboard(validParams);

      expect(result.data!.dateRange.start).toEqual(new Date('2026-01-01'));
      expect(result.data!.dateRange.end).toEqual(new Date('2026-01-31'));
    });

    it('includes a generatedAt timestamp', () => {
      const before = new Date();
      const result = handler.getDashboard(validParams);
      const after = new Date();

      expect(result.data!.generatedAt.getTime()).toBeGreaterThanOrEqual(before.getTime());
      expect(result.data!.generatedAt.getTime()).toBeLessThanOrEqual(after.getTime());
    });

    it('includes recentActivity array', () => {
      const result = handler.getDashboard(validParams);

      expect(Array.isArray(result.data!.recentActivity)).toBe(true);
    });

    it('each metric has the correct shape', () => {
      const result = handler.getDashboard(validParams);

      for (const key of ['orders', 'revenue', 'users', 'conversion'] as const) {
        const metric = result.data!.metrics[key];
        expect(metric.metricType).toBe(key);
        expect(typeof metric.current).toBe('number');
        expect(typeof metric.previous).toBe('number');
        expect(typeof metric.changePercent).toBe('number');
        expect(['up', 'down', 'flat']).toContain(metric.trend);
        expect(Array.isArray(metric.timeSeries)).toBe(true);
      }
    });

    it('respects granularity parameter', () => {
      const result = handler.getDashboard(validParamsWithGranularity);

      expect(result.success).toBe(true);
    });

    it('returns error for invalid params', () => {
      const result = handler.getDashboard({ startDate: '', endDate: '' });

      expect(result.success).toBe(false);
      expect(result.error).toBeDefined();
      expect(result.data).toBeUndefined();
    });

    it('returns error for reversed date range', () => {
      const result = handler.getDashboard({
        startDate: '2026-02-01',
        endDate: '2026-01-01',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('startDate must be before endDate');
    });
  });

  // =========================================================================
  // GET /api/analytics/metrics/:type — full pipeline
  // =========================================================================

  describe('GET /api/analytics/metrics/:type', () => {
    it('returns success for each valid metric type', () => {
      for (const type of ['orders', 'revenue', 'users', 'conversion']) {
        const result = handler.getMetric(type, validParams);

        expect(result.success).toBe(true);
        expect(result.data).toBeDefined();
        expect(result.data!.metricType).toBe(type);
      }
    });

    it('returns correct metric shape', () => {
      const result = handler.getMetric('orders', validParams);

      expect(result.data!.metricType).toBe('orders');
      expect(typeof result.data!.current).toBe('number');
      expect(typeof result.data!.previous).toBe('number');
      expect(typeof result.data!.changePercent).toBe('number');
      expect(['up', 'down', 'flat']).toContain(result.data!.trend);
      expect(Array.isArray(result.data!.timeSeries)).toBe(true);
    });

    it('returns error for invalid metric type', () => {
      const result = handler.getMetric('invalid', validParams);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid metric type');
      expect(result.data).toBeUndefined();
    });

    it('returns error for invalid date params', () => {
      const result = handler.getMetric('orders', {
        startDate: 'bad-date',
        endDate: '2026-01-31',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('valid ISO 8601 dates');
    });

    it('returns error for missing params', () => {
      const result = handler.getMetric('orders', {
        startDate: '',
        endDate: '',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('required');
    });

    it('returns error when both metric type and params are invalid', () => {
      const result = handler.getMetric('bad-type', {
        startDate: '',
        endDate: '',
      });

      // metric type is validated first
      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid metric type');
    });

    it('respects granularity', () => {
      const result = handler.getMetric('revenue', validParamsWithGranularity);

      expect(result.success).toBe(true);
      expect(result.data).toBeDefined();
    });
  });

  // =========================================================================
  // GET /api/analytics/reports/summary — full pipeline
  // =========================================================================

  describe('GET /api/analytics/reports/summary', () => {
    it('returns success with report data for valid params', () => {
      const result = handler.getReportSummary(validParams);

      expect(result.success).toBe(true);
      expect(result.data).toBeDefined();
    });

    it('includes totals with correct fields', () => {
      const result = handler.getReportSummary(validParams);
      const totals = result.data!.totals;

      expect(typeof totals.orders).toBe('number');
      expect(typeof totals.revenue).toBe('number');
      expect(typeof totals.newUsers).toBe('number');
      expect(typeof totals.averageOrderValue).toBe('number');
    });

    it('includes topMetrics array with 3 metrics', () => {
      const result = handler.getReportSummary(validParams);

      expect(result.data!.topMetrics).toHaveLength(3);
      expect(result.data!.topMetrics.map(m => m.metricType)).toEqual([
        'orders',
        'revenue',
        'users',
      ]);
    });

    it('includes dateRange matching the request', () => {
      const result = handler.getReportSummary(validParams);

      expect(result.data!.dateRange.start).toEqual(new Date('2026-01-01'));
      expect(result.data!.dateRange.end).toEqual(new Date('2026-01-31'));
    });

    it('includes generatedAt timestamp', () => {
      const before = new Date();
      const result = handler.getReportSummary(validParams);
      const after = new Date();

      expect(result.data!.generatedAt.getTime()).toBeGreaterThanOrEqual(before.getTime());
      expect(result.data!.generatedAt.getTime()).toBeLessThanOrEqual(after.getTime());
    });

    it('computes averageOrderValue as revenue / orders', () => {
      const result = handler.getReportSummary(validParams);
      const { orders, revenue, averageOrderValue } = result.data!.totals;

      if (orders > 0) {
        expect(averageOrderValue).toBe(revenue / orders);
      } else {
        expect(averageOrderValue).toBe(0);
      }
    });

    it('returns error for invalid params', () => {
      const result = handler.getReportSummary({
        startDate: '',
        endDate: '2026-01-31',
      });

      expect(result.success).toBe(false);
      expect(result.error).toBeDefined();
    });

    it('returns error for invalid granularity', () => {
      const result = handler.getReportSummary({
        startDate: '2026-01-01',
        endDate: '2026-01-31',
        granularity: 'century',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid granularity');
    });
  });

  // =========================================================================
  // Cross-endpoint consistency
  // =========================================================================

  describe('cross-endpoint consistency', () => {
    it('dashboard metrics match individual metric queries', () => {
      const dashboard = handler.getDashboard(validParams);

      for (const type of ['orders', 'revenue', 'users', 'conversion'] as const) {
        const individual = handler.getMetric(type, validParams);

        expect(dashboard.data!.metrics[type].metricType).toBe(
          individual.data!.metricType,
        );
        expect(dashboard.data!.metrics[type].current).toBe(
          individual.data!.current,
        );
        expect(dashboard.data!.metrics[type].previous).toBe(
          individual.data!.previous,
        );
        expect(dashboard.data!.metrics[type].changePercent).toBe(
          individual.data!.changePercent,
        );
        expect(dashboard.data!.metrics[type].trend).toBe(
          individual.data!.trend,
        );
      }
    });

    it('report totals match dashboard metric currents', () => {
      const dashboard = handler.getDashboard(validParams);
      const report = handler.getReportSummary(validParams);

      expect(report.data!.totals.orders).toBe(
        dashboard.data!.metrics.orders.current,
      );
      expect(report.data!.totals.revenue).toBe(
        dashboard.data!.metrics.revenue.current,
      );
      expect(report.data!.totals.newUsers).toBe(
        dashboard.data!.metrics.users.current,
      );
    });

    it('report topMetrics match individual metric queries', () => {
      const report = handler.getReportSummary(validParams);

      for (const metric of report.data!.topMetrics) {
        const individual = handler.getMetric(metric.metricType, validParams);
        expect(metric.current).toBe(individual.data!.current);
        expect(metric.previous).toBe(individual.data!.previous);
      }
    });
  });

  // =========================================================================
  // Error response format consistency
  // =========================================================================

  describe('error response format', () => {
    it('all endpoints return consistent error shape', () => {
      const dashErr = handler.getDashboard({ startDate: '', endDate: '' });
      const metricErr = handler.getMetric('bad', validParams);
      const reportErr = handler.getReportSummary({ startDate: '', endDate: '' });

      for (const err of [dashErr, metricErr, reportErr]) {
        expect(err.success).toBe(false);
        expect(typeof err.error).toBe('string');
        expect(err.data).toBeUndefined();
      }
    });
  });

  // =========================================================================
  // Time-range filtering
  // =========================================================================

  describe('time-range filtering', () => {
    it('accepts various valid date ranges', () => {
      const ranges = [
        { startDate: '2026-01-01', endDate: '2026-01-02' }, // 1 day
        { startDate: '2025-01-01', endDate: '2026-01-01' }, // 1 year
        { startDate: '2026-03-15T00:00:00Z', endDate: '2026-03-15T23:59:59Z' }, // same day with time
      ];

      for (const params of ranges) {
        const result = handler.getDashboard(params);
        expect(result.success).toBe(true);
      }
    });

    it('different date ranges produce independent responses', () => {
      const jan = handler.getDashboard({
        startDate: '2026-01-01',
        endDate: '2026-01-31',
      });
      const feb = handler.getDashboard({
        startDate: '2026-02-01',
        endDate: '2026-02-28',
      });

      expect(jan.data!.dateRange.start).not.toEqual(feb.data!.dateRange.start);
      expect(jan.data!.dateRange.end).not.toEqual(feb.data!.dateRange.end);
    });

    it('all granularities work end-to-end for each endpoint', () => {
      for (const granularity of ['hour', 'day', 'week', 'month']) {
        const params = { startDate: '2026-01-01', endDate: '2026-01-31', granularity };

        expect(handler.getDashboard(params).success).toBe(true);
        expect(handler.getMetric('orders', params).success).toBe(true);
        expect(handler.getReportSummary(params).success).toBe(true);
      }
    });
  });
});

